INSERT INTO fortune_tree_attempt (
  uuid, cycle_id, status, used_count, level, deposit, reward_max, seed, bubble_count, reroll_count,
  created_at_millis, collect_bits, updated_at_millis
) VALUES (
  #{uuid}, #{cycleId}, #{status}, #{usedCount}, #{level}, #{deposit}, #{rewardMax}, #{seed}, #{bubbleCount}, #{rerollCount},
  #{createdAtMillis}, #{collectBits}, #{updatedAtMillis}
)
